const fs = require('fs');
const path = require('path');

// Pasta base - ALTERE AQUI PARA SUA PASTA
const basePath = 'D:\\VibeCoding\\ProjSitesAI';

if (!fs.existsSync(basePath)) {
  throw new Error('Pasta não encontrada: ' + basePath);
}

const dirs = fs.readdirSync(basePath);
const projects = [];

for (const dir of dirs) {
  const projectPath = path.join(basePath, dir);
  const stat = fs.statSync(projectPath);

  if (stat.isDirectory()) {
    // Detecta tipo de projeto
    let type = 'unknown';
    if (fs.existsSync(path.join(projectPath, 'package.json'))) type = 'nodejs';
    if (fs.existsSync(path.join(projectPath, 'composer.json'))) type = 'php';
    if (fs.existsSync(path.join(projectPath, 'wp-config.php'))) type = 'wordpress';
    if (fs.existsSync(path.join(projectPath, 'requirements.txt'))) type = 'python';
    if (fs.existsSync(path.join(projectPath, 'go.mod'))) type = 'go';
    if (fs.existsSync(path.join(projectPath, 'Cargo.toml'))) type = 'rust';

    projects.push({
      name: dir,
      path: projectPath,
      type: type,
      isValid: type !== 'unknown'
    });
  }
}

return [{ json: { projects: projects.filter(p => p.isValid) } }];

